INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '🕌 حق الله على العباد', 'easy', 'mc', 'ما معنى توحيد العبادة؟', '["الواجب عليه أن يرض ى؛ لقول النبي :(و م نْ حُلِف ل هُ بِاللََِّّ ف لْي رْض )", "الدعوة إلى شهادة أن لا إله إلا الله.", "وهو إفراد الله بالعبادة وترك عبادة ما سواه، والبراءة من ذلك", "عظمة الله وبيان استحقاقه للعبادة وحده."]'::jsonb, 2, 'وهو إفراد الله بالعبادة وترك عبادة ما سواه، والبراءة من ذلك.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '🕌 حق الله على العباد', 'medium', 'mc', 'لما بعث النبي معاذًا إلى اليمن إلى ماذا دعا الناس؟', '["الدعوة إلى شهادة أن لا إله إلا الله.", "الواجب عليه أن يرض ى؛ لقول النبي :(و م نْ حُلِف ل هُ بِاللََِّّ ف لْي رْض )", "أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة ", "عظمة الله وبيان استحقاقه للعبادة وحده."]'::jsonb, 2, 'أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 مسائل متنوعة', 'hard', 'mc', 'ماهي الدعوة التي أمر النبي بالقيام بها؟', '["أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة .", "الواجب عليه أن يرض ى؛ لقول النبي :(و م نْ حُلِف ل هُ بِاللََِّّ ف لْي رْض )", "عظمة الله وبيان استحقاقه للعبادة وحده.", "الدعوة إلى شهادة أن لا إله إلا الله"]'::jsonb, 3, 'الدعوة إلى شهادة أن لا إله إلا الله.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 مسائل متنوعة', 'easy', 'mc', 'ما المشروع قوله لمن نزل بقعةً من الأرض؟', '["الدعوة إلى شهادة أن لا إله إلا الله.", "وهو إفراد الله بالعبادة وترك عبادة ما سواه، والبراءة من ذلك.", "«أ عُوذُ بِك لِم اتِ اللهِ التَّام اتِ مِنْ ش ر ِ م ا خ ل ق » ", "أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة ."]'::jsonb, 2, '«أ عُوذُ بِك لِم اتِ اللهِ التَّام اتِ مِنْ ش ر ِ م ا خ ل ق » . أكمليالحديث: «مَنْ نَزَلَ مَنْزِلًَ فَقَالَ : أ عُوذُ بِك لِم اتِ اللهِ التَّام اتِ مِنْ ش ر ِ م ا خ ل ق ، ل مْ ي ضُرَّهُ ش يْءٌ ح تَّى ي رْح ل مِنْ م نْزِلِهِ ذ لِك » . من خلال فهمك لهذا الباب أجيبي على الأسئلة التالية :', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 مسائل متنوعة', 'medium', 'mc', 'ما هو الأثر المترتب على كل من : 1 ) من نزل منزلاً ثم استعا ذ بربه جل وعلا؟', '["وهو إفراد الله بالعبادة وترك عبادة ما سواه، والبراءة من ذلك.", "لم يضره ش يء حتى يرحل من منزله ذلك", "أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة .", "الواجب عليه أن يرض ى؛ لقول النبي :(و م نْ حُلِف ل هُ بِاللََِّّ ف لْي رْض )"]'::jsonb, 1, 'لم يضره ش يء حتى يرحل من منزله ذلك. 2 ) من نزل منزلاً ثم استعاذ بغير ؟ لشيخ الإسلام محمد بن عبدالوهاب رحمه ا 41 ج: زادهم ذلك خوفًا.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 مسائل متنوعة', 'medium', 'mc', 'كيف يكون الغلو في الصالحين؟', '["أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة .", "وهو إفراد الله بالعبادة وترك عبادة ما سواه، والبراءة من ذلك.", "عظمة الله وبيان استحقاقه للعبادة وحده.", "هو: الزيادة في مدحهم، ورفعهم فوق مكانتهم؛ بأن يجعل لهم شيئًا من العبادة"]'::jsonb, 3, 'هو: الزيادة في مدحهم، ورفعهم فوق مكانتهم؛ بأن يجعل لهم شيئًا من العبادة. منصور الغلو في الأمم السابقة : 1 ) النصارى: قالت أن ا لمسيح ابن الله، فرفعوه فوق منزلة البشرية إلى منزلة الربوبية ف يسمونه الرب. 2) اليهود : غلوا في عزير، و قالوا : ابن الله. اذكري مما تعرفين مثالًَ آخر على الغلو في الصالحين : ج: كاعتقاد أن الأولياء لهم تصرف في الكون.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 مسائل متنوعة', 'hard', 'mc', 'ما الواجب على من حُلف له بالله؟', '["وهو إفراد الله بالعبادة وترك عبادة ما سواه، والبراءة من ذلك.", "عظمة الله وبيان استحقاقه للعبادة وحده.", "أول ما بدأ به هو التوحيد شهادة أن لا إله إلا الله ثم الصلاة ثم الزكاة .", "الواجب عليه أن يرض ى؛ لقول النبي :(و م نْ حُلِف ل هُ بِاللََِّّ ف لْي رْض )"]'::jsonb, 3, 'الواجب عليه أن يرض ى؛ لقول النبي :(و م نْ حُلِف ل هُ بِاللََِّّ ف لْي رْض )', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 المؤلف', 'easy', 'mc', 'لماذا هذاالكتاب عظيم جداً ؟', '["قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين", "لأنه يتضمن الحديث عن أمور لا يعذر أحد بجهلها كما أنه يتضمن جواب الأسئلة الثلاثة التي يسأل عنها الإنسان عندما يوضع في قبر", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.", "الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة."]'::jsonb, 1, 'لأنه يتضمن الحديث عن أمور لا يعذر أحد بجهلها كما أنه يتضمن جواب الأسئلة الثلاثة التي يسأل عنها الإنسان عندما يوضع في قبره .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 المؤلف', 'medium', 'mc', 'من أين أخذ المؤلف هذه التسميةبالأص ول الثل ثة؟', '["الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »", "لأنه يتحدث عن الأمور الثلاثة التي يسأل عنها الإنسان في قبره ، فالإنسان يسأل في قبره ثلاثة أسئلة وهي: من ربك ؟ وما دينك ؟", "الاستغاثة : هي طلب الغوث وهو الإنقاذ من الشدة والهلاك ."]'::jsonb, 2, 'لأنه يتحدث عن الأمور الثلاثة التي يسأل عنها الإنسان في قبره ، فالإنسان يسأل في قبره ثلاثة أسئلة وهي: من ربك ؟ وما دينك ؟ ومن نبيك ؟', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 المؤلف', 'hard', 'mc', 'ماذا تعرف عن مؤلف الكتاب ؟', '["الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3.]", "أي طريقُ هُ الد يني الذي يسير عليه الن ي .", "نشأ في بيئة صالحة و حفظ القر آن الكريم قبل سن العاشرة ، وكان سريع الفهم وأخذ العلم عن والده ثم رحل في طل ب العلم إلى ال ", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163]."]'::jsonb, 2, 'نشأ في بيئة صالحة و حفظ القر آن الكريم قبل سن العاشرة ، وكان سريع الفهم وأخذ العلم عن والده ثم رحل في طل ب العلم إلى ال بصرة والإحساء وال ى الأسئلة الأصول الثلاثة- للمبتدئين الحجاز... وغيرها .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 المؤلف', 'easy', 'mc', 'من أهم شيوخ المؤلف؟', '["الدليل قوله تعالى: ﱥﭐ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸﱹ ﱤ [النساء: 165].", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين", "للمصنف عدد كبير من المشايخ منهم: 1) الشيخ محمد حياة السندي"]'::jsonb, 3, 'للمصنف عدد كبير من المشايخ منهم: 1) الشيخ محمد حياة السندي. 2) الشيخ عبدالله بن إبراهيم الن جدي . 3) الشيخ عبدالله بن إبراهيم الشمري وغيرهم', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 المؤلف', 'medium', 'mc', 'ما أهممؤلفات المصنف؟', '["ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة.", "للمصنف عد ة مؤلفات أهمها: 1) كتاب التوحيد ", "هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة.", "هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به."]'::jsonb, 1, 'للمصنف عد ة مؤلفات أهمها: 1) كتاب التوحيد . 2) كتاب كشف الشبهات. 3) كتاب الأصول الثلاثة وغيرها', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما هو تعريف العلم ؟', '["دليل الحج قوله تعالى: ﱥﭐ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﱤ [ورة آل عمران : 97.]", "رجاء الإنسان في لقاء ربه في الآخرة.", "أول مرتبة الإسلام.", "العلم هو إدراك الش يء على حقيقته إدراكً ا جازمً ا"]'::jsonb, 3, 'العلم هو إدراك الش يء على حقيقته إدراكً ا جازمً ا. قال المصنف: «يجب علينا تعلم أربع مسائل» .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'لماذا بدأ بهذه المسائل؟', '["أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "الدليل قوله تعالى: ﱥﭐ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﱤ [التغابن: 7].", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم", "أول مرتبة الإسلام."]'::jsonb, 2, 'لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما حكم تعلم هذه المسائل؟', '["حكمها واجب والواجب ما يثاب فاعله ويعاقب تار كه", "الدليل قوله تعالى: ﱥﭐ ﲬ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﲳ ﲴ ﲵ ﲶ ﲷ ﲸﲹ ﲺ ﲻ ﲼ ﲽ ﱤ [سورة البينة: 5].", "هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "المرتبة الثانية الإيمان."]'::jsonb, 0, 'حكمها واجب والواجب ما يثاب فاعله ويعاقب تار كه. من أراد أن يتعلم دين الله لا بد له من هذه المسائل.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ما هي الأدلة من كتاب الله التي تحث على العلم؟', '["الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 .]", "الأدلة من كتاب الله تعالى: 1) قوله تعالى: ﱥﭐ ﳘ ﳙ ﳚ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﳡ ﳢ ﳣ ﳤ ﳥ ﱤ [سورة المجادلة:11]", "الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.", "المرتبة الثانية الإيمان."]'::jsonb, 1, 'الأدلة من كتاب الله تعالى: 1) قوله تعالى: ﱥﭐ ﳘ ﳙ ﳚ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﳡ ﳢ ﳣ ﳤ ﳥ ﱤ [سورة المجادلة:11]. 2) قوله تعالى: ﱥﭐ ﳁ ﳂ ﳃ ﳄ ﳅ ﳆ ﳇ ﳈﳉ ﳊ ﳋ ﳌ ﳍ ﱤ [سورة الزم ر:9] . اسئلة لشيخ الإسلام محمد بن عبدالوهاب رحمه الله 3) قوله تعالى: ﱥﭐ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲﲳ ﲴ ﲵ ﲶ ﲷ ﱤ [سورة فاطر: 18 ]', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '🕌 الرب', 'easy', 'mc', 'بم يعرف المسلم ربه؟', '["يعرف المسلم ربه بأربعة أمور وهي: 1) إفراده بوجوده الأبدي 2) إفراده بالربوبية المطلقة 3) إفراده بالألوهية المستحقة 4) إفر", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "رجاء الإنسان في لقاء ربه في الآخرة."]'::jsonb, 0, 'يعرف المسلم ربه بأربعة أمور وهي: 1) إفراده بوجوده الأبدي 2) إفراده بالربوبية المطلقة 3) إفراده بالألوهية المستحقة 4) إفراد ه بأسمائه وصفاته الحسنى.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'بم ي عرف المسلم نبيه ؟', '["ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة.", "يعرف المسلم نبيه بخمسة أمور هي: 1) قبول ما جاء به واتباعه واتخاذه أسوة وقدوة", "مراتب الإسلام ثلاث مراتب .", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة ."]'::jsonb, 1, 'يعرف المسلم نبيه بخمسة أمور هي: 1) قبول ما جاء به واتباعه واتخاذه أسوة وقدوة. 2) طاعته فيما أمر 3) تصديقه فيما أخبر 4) اجتناب ما نهى عنه وزجر 5) أن لا يعبد الله إلا بما شرعه رسول .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'لماذا ذكر المصنف العمل بالعلم؟', '["الاستعاذة: هي طلب الحماية من مكروه.", "لأن العلم لا ينفع إلا ب العمل، فالإنسان لا بد له أن يعلم ويعرف ربه ويعرف نبيه ويعرف دينه قبل العمل حتى يعمل على علم وبصي", "هو طمع الإنسان في أمر قريب المنال يمكن أن ي ناله.", "الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3.]"]'::jsonb, 1, 'لأن العلم لا ينفع إلا ب العمل، فالإنسان لا بد له أن يعلم ويعرف ربه ويعرف نبيه ويعرف دينه قبل العمل حتى يعمل على علم وبصيرة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📚 المسائل الأربع', 'easy', 'mc', 'ما فائدة الدعوة إلى الدين؟', '["الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة.", "الدليل قوله تعالى: ﱥﭐ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸﱹ ﱤ [النساء: 165].", "الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].", "تكون الدعوة وفق ما جاء في النصوص الشرعية وعلى فهم السلف الصالح وبالوسائل المناسبة، قال تعالى: ﱥﲖ ﲗ ﲘ ﲙ ﲚ ﲛ ﲜ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ"]'::jsonb, 3, 'تكون الدعوة وفق ما جاء في النصوص الشرعية وعلى فهم السلف الصالح وبالوسائل المناسبة، قال تعالى: ﱥﲖ ﲗ ﲘ ﲙ ﲚ ﲛ ﲜ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﲮ ﱤ [سورة النحل: 125].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما الدليل على تعلم هذه المسائل الأربع؟', '["الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3", "الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.", "الدليل قوله تعالى: ﱥﭐ ﲬ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﲳ ﲴ ﲵ ﲶ ﲷ ﲸﲹ ﲺ ﲻ ﲼ ﲽ ﱤ [سورة البينة: 5].", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] ."]'::jsonb, 0, 'الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3.]', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما هي أقسام الصبر؟', '["أقسام الصبر ثلاثة: 1) صبر على طاعة 2) صبر عن محارم الله", "الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "المرتبة الثانية الإيمان.", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية ."]'::jsonb, 0, 'أقسام الصبر ثلاثة: 1) صبر على طاعة 2) صبر عن محارم الله. 3) صبر على أقدار الله التي يجريها إما مما لا كسب للعباد فيه، وإما مما يجريه الله على أيدي بعض العباد من الإيذاء والاعتداء.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما المراد بالعصر؟', '["الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3.]", "أي طريقُ هُ الد يني الذي يسير عليه الن ي .", "أقسم الله في هذه الس ورة بالعصر الذي هو الدهر وهو محل الحوادث من خير وشر ", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله."]'::jsonb, 2, 'أقسم الله في هذه الس ورة بالعصر الذي هو الدهر وهو محل الحوادث من خير وشر .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما المراد بالعمل الصالح؟', '["الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »", "أول مرتبة الإسلام.", "العمل الصالح هو العمل الموافق لسنة رسول الله ", "الصلوات الخمس المفروضة."]'::jsonb, 2, 'العمل الصالح هو العمل الموافق لسنة رسول الله .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ماذا قال الشافعي في هذه السورة؟', '["قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم ", "الصلوات الخمس المفروضة.", "الذي رباني بنعمه وهو المستحق للعبادة دون سواه.", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163]."]'::jsonb, 0, 'قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما هي الأدلة على «أنخلقنا»؟', '["الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك وأهله .", "قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين", "الأدلة كثيرة منها: 1) قوله تعالى : ﱥﭐ ﱑ ﱒ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘﱙ ﱚ ﱛ ﱜﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [نعام: 2]"]'::jsonb, 3, 'الأدلة كثيرة منها: 1) قوله تعالى : ﱥﭐ ﱑ ﱒ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘﱙ ﱚ ﱛ ﱜﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [نعام: 2]. 2) وقوله تعالى : ﱥﭐ ﱿ ﲀ ﲁ ﲂﲃ ﱤ [سورة الزمر : 62]. 3) وقوله ﱥﭐ ﲤ ﲥ ﲦ ﲧ ﲨ ﱤ [سورة الصافات: 96]. 4) وقوله: ﱥﭐ ﱣ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱤ [سورة الذاريات: 56] . متنُ الكتاب الأسئلة الأصول الثلاثة- للمبتدئين 5) وقوله تعالى: ﱥﭐ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱢ ﱤ [سورة الطور : 35].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما الغاية من خلق الناس؟', '["الغاية هي عبادة الله كما في الكتاب والسنة قال تعالى: ﱥﭐ ﱣ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱤ [سورة ال ذاريات: 56] ", "هي الطريقة المائلة عن الشرك إلى التوحيد .", "الاستعانة : هي طلب العون من الله.", "الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31]."]'::jsonb, 0, 'الغاية هي عبادة الله كما في الكتاب والسنة قال تعالى: ﱥﭐ ﱣ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱤ [سورة ال ذاريات: 56] .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 النبي', 'easy', 'mc', 'ما الدليل على أن من أطاع الرسول دخل الجنة ومن عصاه دخل النار؟', '["الذبح :هو إزهاق الروح بإراقة الدم على وجه مخصوص .", "الدليل قوله :«م نْ أ ط اع نِي ف ق دْ أ ط اع اللََّّ ، و م نْ لشيخ الإسلام محمد بن عبدالوهاب رحمه الله ع ص انِي ف ق دْ ع ", "القصَد، وال توجَّه .", "أي طريقُ هُ الد يني الذي يسير عليه الن ي ."]'::jsonb, 1, 'الدليل قوله :«م نْ أ ط اع نِي ف ق دْ أ ط اع اللََّّ ، و م نْ لشيخ الإسلام محمد بن عبدالوهاب رحمه الله ع ص انِي ف ق دْ ع ص ى اللََّّ ، و م نْ أ ط اع أ مِيرِي ف ق دْ أ ط اع نِي، و م نْ ع ص ى أ مِيرِي ف ق دْ ع ص انِي » متفق عليه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما هي الحنيفية ؟', '["هي الطريقة المائلة عن الشرك إلى التوحيد ", "دليل الحج قوله تعالى: ﱥﭐ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﱤ [ورة آل عمران : 97.]", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "الذي رباني بنعمه وهو المستحق للعبادة دون سواه."]'::jsonb, 0, 'هي الطريقة المائلة عن الشرك إلى التوحيد .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما معنى ملة إبراهيم؟', '["الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].", "أي طريقُ هُ الد يني الذي يسير عليه الن ي ", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله."]'::jsonb, 1, 'أي طريقُ هُ الد يني الذي يسير عليه الن ي .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'من هو إبراهيم الذي أمرنا باتباع ملته؟', '["الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "إبراهيم هو خليل الرحمن قال :ﱥﭐ ﲎ ﲏ ﲐ ﲑ ﱤ [النساء: 125]رة من القرآن متنُ الكتاب الأسئلة لشيخ الإسلام محمد بن عبدالوهاب رح", "الب ضع بكسر الباء العدد من الثلاثة إلى التسعة ."]'::jsonb, 2, 'إبراهيم هو خليل الرحمن قال :ﱥﭐ ﲎ ﲏ ﲐ ﲑ ﱤ [النساء: 125]رة من القرآن متنُ الكتاب الأسئلة لشيخ الإسلام محمد بن عبدالوهاب رحمه الله للاقتداء به.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما الأصل في بني آدم التوحيد أم ا لشرك ؟', '["التوحيد لأنهم خُ لقوا على الفطرة وعلى التوحيد كما قال تعالى : ﱥﲨ ﲩ ﲪ ﲫ ﲬ ﲭﲮ ﱤ الآ ية", "الاستعانة : هي طلب العون من الله.", "المرتبة الثانية الإيمان.", "الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله"]'::jsonb, 0, 'التوحيد لأنهم خُ لقوا على الفطرة وعلى التوحيد كما قال تعالى : ﱥﲨ ﲩ ﲪ ﲫ ﲬ ﲭﲮ ﱤ الآ ية. و قَالَ النَّ يُّ « :م ا مِنْ م وْلُودٍ إِلاَّ يُول دُ ع ل ى الْ فِطْر ةِ، ف أ ب و اهُ يُه و ِد انِهِ أ وْ يُن ص ِر انِهِ أ وْ يُم ج ِس انِهِ، ك م ا تُنْت جُ الْب هِيم ةُ ب هِيم ةً ج مْع اء ، ه لْ تُحِسُّون فِيه ا مِنْ ج دْع اء » متفق عليه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما المراد بملة إبر اهيم ؟', '["الذبح :هو إزهاق الروح بإراقة الدم على وجه مخصوص .", "الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.", "ملة إبراهيم دينه وطريق ت ه التي سار علمها في الدعوة إلى الله ", "الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »"]'::jsonb, 2, 'ملة إبراهيم دينه وطريق ت ه التي سار علمها في الدعوة إلى الله . الأصول الثلاثة- للمبتدئين ثم قال المصنف : «وأ عْظ مُ م ا أ م ر اللهُ بِهِ التَّوْحيِدُ و هُو : إفراد الله بالعبادة » .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'easy', 'mc', 'لماذا نص المصنف على هذه الأ سئلة الثلثة؟', '["لأنها الأسئلة التي يُسأل عنها الإنسان إذا وضع في قبره", "دليل الحج قوله تعالى: ﱥﭐ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﱤ [ورة آل عمران : 97.]", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله.", "أقسم الله في هذه الس ورة بالعصر الذي هو الدهر وهو محل الحوادث من خير وشر ."]'::jsonb, 0, 'لأنها الأسئلة التي يُسأل عنها الإنسان إذا وضع في قبره. متنُ الكتاب الأسئلة لشيخ الإسلام محمد بن عبدالوهاب رحمه الله متنُ الكتاب قال المصنف :ِي اللهُ الَّذِي ر بَّانِي « و ر بَّى ج مِيع الْع الم ِين بِنِ ع مِ هِ و هُو م عْبُودِي ل يْس لِي م عْبُود سِو اهُ و الدَّلِيلُ قو له تعالى: ﱥﭐ ﱆ ﱇ ﱈ ﱉ ﱊ ﱤ [الفاتحة: 2 ]وكل ما سوى الله عالم» .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '🕌 الرب', 'hard', 'mc', 'ما الدليل على أن الرب هو المتفضل بالنعم؟', '["لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.", "الذي رباني بنعمه وهو المستحق للعبادة دون سواه.", "رجاء الإنسان في لقاء ربه في الآخرة.", "الدليل قول الله تعالى في محاورة موس ى مع عدوفرعون : ﱥﭐ ﳘ ﳙ ﳚ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﳡ ﳢ ﳣ ﳤ ﳥ ﳦ ﱤ [ طه: 49-50]"]'::jsonb, 3, 'الدليل قول الله تعالى في محاورة موس ى مع عدوفرعون : ﱥﭐ ﳘ ﳙ ﳚ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﳡ ﳢ ﳣ ﳤ ﳥ ﳦ ﱤ [ طه: 49-50].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'كم أنواع الآيات الدالة على الخالق؟', '["قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين", "هو اعتقاد بالقلب؛ وقول اللسان؛ وعمل الجوا رح.", "نوعان : 1) آيات كونية : هي المخلوقات", "هو طمع الإنسان في أمر قريب المنال يمكن أن ي ناله."]'::jsonb, 2, 'نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'أنواع العبادة نوعان فما هما؟', '["1) دعاء مسألة: ما فيه سؤال وطلب أي : ما يطلب الإنسان من ربهاللَّهُمَّ اغْفِرْ متنُ الكتاب الأسئلة لشيخ الإسلام محمد بن ع", "الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة.", "القصَد، وال توجَّه .", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم."]'::jsonb, 0, '1) دعاء مسألة: ما فيه سؤال وطلب أي : ما يطلب الإنسان من ربهاللَّهُمَّ اغْفِرْ متنُ الكتاب الأسئلة لشيخ الإسلام محمد بن عبدالوهاب رحمه الله لِي و ارْح مْنِي » متفق عليه. 2) دعاء عبادة : مثل الصلاة والصيام يعني ما لا طلب فيه. الأصول الثلاثة- للمبتدئين قال المصنف :«ﱥﭐ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱤ [آل عمران : 175] .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما الرجاء المشار إليه في الآية؟', '["الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31].", "الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128].", "الدليل قوله تعالى : ﱥﭐ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶ ﱤ [المائدة: 3].", "رجاء الإنسان في لقاء ربه في الآخرة"]'::jsonb, 3, 'رجاء الإنسان في لقاء ربه في الآخرة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'إلى كم قسم ينقسم الرجاء؟', '["الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 .]", "هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة", "الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128].", "الب ضع بكسر الباء العدد من الثلاثة إلى التسعة ."]'::jsonb, 1, 'هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'easy', 'mc', 'ما هي معاني المصطلحات التالية: الرغ بة و الره بة و الخشوع؟', '["الاستعانة : هي طلب العون من الله.", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] .", "الرغبة: هي محبة الوصول إلى الش يء المحبوب", "الخشية : هي الخوف المبني على العلم."]'::jsonb, 2, 'الرغبة: هي محبة الوصول إلى الش يء المحبوب. الرهبة : الخوف المثمر للهرب من المخوف فهي خوف مقرون بعمل. الخشوع: هو الذل لعظمة الله بحيث يستسلم لقضائه. متنُ الكتاب الأسئلة لشيخ الإسلام محمد بن عبدالوهاب رحمه الله قال المصنف :«ﱥﭐ ﲜ ﲝ ﲞ ﱤ [ةالبقرة : 150 ]» .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما المراد ب الخشية؟', '["الخشية : هي الخوف المبني على العلم", "هو اعتقاد بالقلب؛ وقول اللسان؛ وعمل الجوا رح.", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163]."]'::jsonb, 0, 'الخشية : هي الخوف المبني على العلم.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما حكم الخشية من الخلق؟', '["وللخشية ثلاثة أنواع : 1) خشية طبعية : ك الخ شية من النار ومن السبع وهذا لا يلام عليه إذا كان لها دواعي", "الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك وأهله .", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.", "الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31]."]'::jsonb, 0, 'وللخشية ثلاثة أنواع : 1) خشية طبعية : ك الخ شية من النار ومن السبع وهذا لا يلام عليه إذا كان لها دواعي. 2) خشية عبادة وهي :أن يخش ى الإنسان من الله و يتعبد له بهذه الخشية وهذه من التوحيد. 3) خشيةالسر وهي : الخشية من صاحب القبر أو الولي وهذا شرك أكبر. متنُ الكتاب الأسئلة الأصول الثلاثة- للمبتدئين قال المصنف :«ﱥﭐ ﲫ ﲬ ﲭ ﲮ ﲯ ﱤ [الزمر : 54]» .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما هي الإ نابة؟', '["الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.", "الدليل قوله تعالى : ﱥﭐ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶ ﱤ [المائدة: 3].", "هاجر إلى المدينة النبوية.", "الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة"]'::jsonb, 3, 'الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'ما المراد بالإسلم في الآية؟', '["هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة.", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.", "هو طمع الإنسان في أمر قريب المنال يمكن أن ي ناله.", "الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية"]'::jsonb, 3, 'الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الاستعاذة', 'easy', 'mc', 'ما معنى الاستعاذة ؟', '["الذبح :هو إزهاق الروح بإراقة الدم على وجه مخصوص .", "الاستعاذة: هي طلب الحماية من مكروه", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "القصَد، وال توجَّه ."]'::jsonb, 1, 'الاستعاذة: هي طلب الحماية من مكروه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما معنى الاستغاثة ؟', '["الخشية : هي الخوف المبني على العلم.", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128].", "الاستغاثة : هي طلب الغوث وهو الإنقاذ من الشدة والهلاك "]'::jsonb, 3, 'الاستغاثة : هي طلب الغوث وهو الإنقاذ من الشدة والهلاك .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '🤲 الدعاء', 'hard', 'mc', 'ما المراد بالذبح ؟', '["الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.", "الذبح :هو إزهاق الروح بإراقة الدم على وجه مخصوص ", "الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].", "أي طريقُ هُ الد يني الذي يسير عليه الن ي ."]'::jsonb, 1, 'الذبح :هو إزهاق الروح بإراقة الدم على وجه مخصوص .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما المراد بالإسلم ؟', '["دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] .", "الدليل قوله تعالى: ﱥﭐ ﲬ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﲳ ﲴ ﲵ ﲶ ﲷ ﲸﲹ ﲺ ﲻ ﲼ ﲽ ﱤ [سورة البينة: 5].", "الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك وأهله ", "العمل الصالح هو العمل الموافق لسنة رسول الله ."]'::jsonb, 2, 'الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك وأهله .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'كم مراتب الإسلم؟', '["مراتب الإسلام ثلاث مراتب ", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة ."]'::jsonb, 0, 'مراتب الإسلام ثلاث مراتب .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما هي مراتب الإسلم؟', '["الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].", "حديث جبريل الذي قال الن ي في نهايته «ف إِنَّهُ جبريل أتاكم يعلمكم دينكم» متفق عليه.", "الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة.", "مراتب الإسلام هي: متنُ الكتاب الأسئلة الأصول الثلاثة- للمبتدئين المرتبة الأولى :الإسلام "]'::jsonb, 3, 'مراتب الإسلام هي: متنُ الكتاب الأسئلة الأصول الثلاثة- للمبتدئين المرتبة الأولى :الإسلام . المرتبة الثانية :الإيمان. المرتبة الثالثة :الإحسان .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'ما هو الدليل على أن الدين ثلث مراتب؟', '["أي طريقُ هُ الد يني الذي يسير عليه الن ي .", "الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128].", "حديث جبريل الذي قال الن ي في نهايته «ف إِنَّهُ جبريل أتاكم يعلمكم دينكم» متفق عليه", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة ."]'::jsonb, 2, 'حديث جبريل الذي قال الن ي في نهايته «ف إِنَّهُ جبريل أتاكم يعلمكم دينكم» متفق عليه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ما هي أول مرتبة من مراتب الإسلم؟', '["أول مرتبة الإسلام", "الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].", "الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "الخشية : هي الخوف المبني على العلم."]'::jsonb, 0, 'أول مرتبة الإسلام.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'easy', 'mc', 'ما هي أركان الإسلم؟', '["الدليل قوله تعالى : ﱥﭐ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶ ﱤ [المائدة: 3].", "الذي رباني بنعمه وهو المستحق للعبادة دون سواه.", "قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين", "أركان الإسلام خمسة؛ شهادة أن لا إله إلا الله وأن محمدً ا رسول الله وإقام الصلاة وإيتاء الزكاة والحج وصوم رمضان"]'::jsonb, 3, 'أركان الإسلام خمسة؛ شهادة أن لا إله إلا الله وأن محمدً ا رسول الله وإقام الصلاة وإيتاء الزكاة والحج وصوم رمضان.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما الدليل على شهادة أن لا إله إالله؟', '["الاستغاثة : هي طلب الغوث وهو الإنقاذ من الشدة والهلاك .", "الذبح :هو إزهاق الروح بإراقة الدم على وجه مخصوص .", "هو طمع الإنسان في أمر قريب المنال يمكن أن ي ناله.", "الدليل قوله تعالى: ﱥﭐ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟﱠ ﱡ ﱢ ﱣ ﱤ ﱥ ﱦ ﱧ ﱤ [سورة آل عمران : 18]"]'::jsonb, 3, 'الدليل قوله تعالى: ﱥﭐ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟﱠ ﱡ ﱢ ﱣ ﱤ ﱥ ﱦ ﱧ ﱤ [سورة آل عمران : 18]. متنُ الك تاب الأسئلة الأصول الثلاثة- للمبتدئين', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '🙏 العبادة', 'hard', 'mc', 'ما معنى شهادة أن لا إله إلا الله؟', '["العمل الصالح هو العمل الموافق لسنة رسول الله .", "ومعناها لا معبود بحق إلا الله «لا إله» نافيًا جميع ما يعبد من دون الله «إ» مثبتًا العبادة لله وحده لا شريك له في عبادته ", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم.", "مراتب الإسلام ثلاث مراتب ."]'::jsonb, 1, 'ومعناها لا معبود بحق إلا الله «لا إله» نافيًا جميع ما يعبد من دون الله «إ» مثبتًا العبادة لله وحده لا شريك له في عبادته كما أنه لا شريك له في ملكه .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما الدليل على معنى شهادةأن لا إله إلا الله؟', '["الدليل قوله تعالى: ﱥﭐ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸ ﱹ ﱺ ﱻ ﱼ ﱽ ﱾ ﱿ ﲀ ﲁ ﲂ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﱤ [ الزخرف : 26-28] ", "الهجرة فريضة على هذه الأمة من بلد الشرك إلى بلد الإسلام، وهي باقية إلى أن تقوم الساعة.", "الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].", "هو طمع الإنسان في أمر قريب المنال يمكن أن ي ناله."]'::jsonb, 0, 'الدليل قوله تعالى: ﱥﭐ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸ ﱹ ﱺ ﱻ ﱼ ﱽ ﱾ ﱿ ﲀ ﲁ ﲂ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﱤ [ الزخرف : 26-28] . وقوله ﱥﭐ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱢ ﱣ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲﱳ ﱴ ﱵ ﱶ ﱷ ﱸ ﱹ ﱺ ﱤ [ آل عمران : 64] .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '🙏 العبادة', 'medium', 'mc', 'ما هي أركان لا إله إلا اله ؟', '["الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "أول مرتبة الإسلام.", "أركان شها دة أن لا إله إلا الله اثنان هما: الركن الأول : نفي وهو قول : «لا إله»", "الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3.]"]'::jsonb, 2, 'أركان شها دة أن لا إله إلا الله اثنان هما: الركن الأول : نفي وهو قول : «لا إله». الركن الثاني :إثبات العبادة لله وحده في قول : «إ».', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما معنى شهادة أن محمدًا رسول الله ؟', '["الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 .]", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "ومعنى شهادة أن محمدً ا رسول الله: طاعته فيما أمر، وتصديقه فيم ا أخبر، واجتناب ما عنه نهى وزجر، وأن لا يعبد الله إلا بما ", "قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين"]'::jsonb, 2, 'ومعنى شهادة أن محمدً ا رسول الله: طاعته فيما أمر، وتصديقه فيم ا أخبر، واجتناب ما عنه نهى وزجر، وأن لا يعبد الله إلا بما شرع.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما الدليل على أن محمدًا أرسله الله للخلق؟', '["هي الطريقة المائلة عن الشرك إلى التوحيد .", "الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 .]", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "دليل أن محمدً ا رسول من الله قوله تعالى: ﱥﭐ ﲜ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﱤ [التوبة: 128] "]'::jsonb, 3, 'دليل أن محمدً ا رسول من الله قوله تعالى: ﱥﭐ ﲜ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﱤ [التوبة: 128] . وقوله تعالى: ﱥﭐ ﱁ ﱂ ﱃﱄ ﱤ [ الفتح: 29] .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما هي الصلة المذكورة في أركان الإسلم؟', '["الاستغاثة : هي طلب الغوث وهو الإنقاذ من الشدة والهلاك .", "القصَد، وال توجَّه .", "الاستعانة : هي طلب العون من الله.", "الصلوات الخمس المفروضة"]'::jsonb, 3, 'الصلوات الخمس المفروضة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ما الدليل على أن الله افترض علينا خمس صلوات في اليوم والليلة؟', '["الصلوات الخمس المفروضة.", "الدليل قوله في وصيته لمعاذ :«ف أ عْلِمْهُمْ أ ن اللََّّ ق دِ افْت ر ض ع ل يْهِمْ خ مْس ص ل و اتٍ فِ ي كُل ِ ي وْمٍ و ل ي", "الإسلام الشرعي وهو الاستسلام لأحكام الله الشرع ية.", "أي طريقُ هُ الد يني الذي يسير عليه الن ي ."]'::jsonb, 1, 'الدليل قوله في وصيته لمعاذ :«ف أ عْلِمْهُمْ أ ن اللََّّ ق دِ افْت ر ض ع ل يْهِمْ خ مْس ص ل و اتٍ فِ ي كُل ِ ي وْمٍ و ل يْل ةٍ » متفق عليه. وقوله في جوابه لسؤال الأعرابي الذي جاء يسأل عن الإسلام «خ مْسُ ص ل و اتٍ فِي الْي وْمِ و اللَّيْل ةِ »، فَقَالَ: هَلْ عَلَيَّ غَيْرُهَا؟ قَالَ: «لا ، إِلاَّ أ نْ ت طَّوَّع » رواه البخاري .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما معنى إيتاء الزكاة؟', '["الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية ", "الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »", "الدليل قوله تعالى: ﱥﭐ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﱤ [التغابن: 7]."]'::jsonb, 1, 'نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما هي مصارف الزكاة؟', '["الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 .]", "مصارف الزكاة هي المذكورة في قوله تعالى: ﱥﭐ ﲐ ﲑ ﲒ ﲓ الأصول الثلاثة- للمبتدئين ﲔ ﲕ ﲖ ﲗ ﲘ ﲙ ﲚ ﲛ ﲜ ﲝ ﲞ ﲟ ﲠﲡ ﲢ ﲣ ﲤﲥ ﲦ ﲧ ﲨ ﲩ ﱤ", "ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة."]'::jsonb, 2, 'مصارف الزكاة هي المذكورة في قوله تعالى: ﱥﭐ ﲐ ﲑ ﲒ ﲓ الأصول الثلاثة- للمبتدئين ﲔ ﲕ ﲖ ﲗ ﲘ ﲙ ﲚ ﲛ ﲜ ﲝ ﲞ ﲟ ﲠﲡ ﲢ ﲣ ﲤﲥ ﲦ ﲧ ﲨ ﲩ ﱤ [ التوبة: 60].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما الدليل على هذه الأركان؟', '["الدليل قوله تعالى: ﱥﭐ ﲬ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﲳ ﲴ ﲵ ﲶ ﲷ ﲸﲹ ﲺ ﲻ ﲼ ﲽ ﱤ [سورة البينة: 5]", "هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "الاستعاذة: هي طلب الحماية من مكروه."]'::jsonb, 0, 'الدليل قوله تعالى: ﱥﭐ ﲬ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﲳ ﲴ ﲵ ﲶ ﲷ ﲸﲹ ﲺ ﲻ ﲼ ﲽ ﱤ [سورة البينة: 5].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما معنى صوم رمضان؟', '["الاستعانة : هي طلب العون من الله.", "الإمساك عن المفطرات بنية مخصوصة في زمن مخصوص", "هاجر إلى المدينة النبوية.", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله."]'::jsonb, 1, 'الإمساك عن المفطرات بنية مخصوصة في زمن مخصوص. وهو الإمساك عن المفطرات بنية عبادة الله في أيام شهر رمضان.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما الدليل على صوم شهر رمضان؟', '["هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة.", "الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك وأهله .", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] ", "ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة."]'::jsonb, 2, 'دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما المراد بحج بيت الله الحرام؟', '["هاجر إلى المدينة النبوية.", "قصد بيت الله الحرام في وقت مخصوص لعبادة مخصوصة وبنية مخصوصة وبصفة مخصوصة؛ وذلك بأن يقصد بيت الله الحرام في مكة المكرمة و", "الاستعانة : هي طلب العون من الله.", "لأنها أمر ضروري لا بد منه لكل من أراد أن يتعلم العلم."]'::jsonb, 1, 'قصد بيت الله الحرام في وقت مخصوص لعبادة مخصوصة وبنية مخصوصة وبصفة مخصوصة؛ وذلك بأن يقصد بيت الله الحرام في مكة المكرمة والمشاعر المقدسة في شهور الحج لأداء نسك الحج في الوقت المخصوص بنية أداء عبادة الحج خالصة لوجه الله كما فعلها ا لن ي . الأصول الثلاثة- للمبتدئين', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما الدليل على فرضية الحج؟', '["دليل الحج قوله تعالى: ﱥﭐ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﱤ [ورة آل عمران : 97", "الإنابة هي الرجوع إلى الله بفعل طاعته واجتن اب معصيته وهي بمعنى التوبة.", "رجاء الإنسان في لقاء ربه في الآخرة.", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية ."]'::jsonb, 0, 'دليل الحج قوله تعالى: ﱥﭐ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﱤ [ورة آل عمران : 97.]', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ما هي المرتبة الثانية من مراتب الدين؟', '["الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "المرتبة الثانية الإيمان", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31]."]'::jsonb, 1, 'المرتبة الثانية الإيمان.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'كم شعب الإيمان وما الدليل على ذلك؟', '["الب ضع بكسر الباء العدد من الثلاثة إلى التسعة .", "بضع وسبعون شعبة كما في الحديث عن الن ي قال «الإِيم انُ بِضْع و س بْعُون شُعْب ةً", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة."]'::jsonb, 1, 'بضع وسبعون شعبة كما في الحديث عن الن ي قال «الإِيم انُ بِضْع و س بْعُون شُعْب ةً. و الْح ي اءُ شُعْب ة مِن الإيمان » رواهمسلم.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما المراد بالبِ ضع؟', '["هي الطريقة المائلة عن الشرك إلى التوحيد .", "القصَد، وال توجَّه .", "الب ضع بكسر الباء العدد من الثلاثة إلى التسعة ", "أي طريقُ هُ الد يني الذي يسير عليه الن ي ."]'::jsonb, 2, 'الب ضع بكسر الباء العدد من الثلاثة إلى التسعة .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'easy', 'mc', 'ما هي أركان الإيمان؟', '["هي الطريقة المائلة عن الشرك إلى التوحيد .", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله.", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "أركان الإيمان ستة؛ أن تؤمن بالله، وملائكته، وكتبه، ورسله، واليوم الآخر، وتؤمن بالقدر خيره وشره"]'::jsonb, 3, 'أركان الإيمان ستة؛ أن تؤمن بالله، وملائكته، وكتبه، ورسله، واليوم الآخر، وتؤمن بالقدر خيره وشره. والدليل على هذه الأركان الستة: قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱒ ﱓ ﱤ [ورة البقرة : 177]. لشيخ الإسلام محمد بن عبدالوهاب رحمه الله ودليل القدر: قوله تعالى: ﱥﭐ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﱤ [ القمر: 49].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'ماذا يتضمن الإيمان؟', '["الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "هي الطريقة المائلة عن الشرك إلى التوحيد .", "يتضمن الإيمان أربعة أمور: 1) الإيمان بوجود ", "الخشية : هي الخوف المبني على العلم."]'::jsonb, 2, 'يتضمن الإيمان أربعة أمور: 1) الإيمان بوجود . 2) الإيمان بربوبيته . 3) الإيمانبألوهيته. 4) الإيمان بأسمائه وصفاته.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ماذا يتضمن الإيمان بالملئكة؟', '["يتضمن الإيمان بالملا ئكة أر بعة أمور وهي: 1) الإيمان بوجودهم ", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] .", "الاستعاذة: هي طلب الحماية من مكروه.", "الدليل قوله تعالى: ﱥﭐ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸﱹ ﱤ [النساء: 165]."]'::jsonb, 0, 'يتضمن الإيمان بالملا ئكة أر بعة أمور وهي: 1) الإيمان بوجودهم . 2) الإيمان بمن علمنا اسمه كجبريل ومن لم نعلم اسمه نؤمن بهم. 3) الإيمان بما علمنا من صفاتهم. 4) الإيمان بما علمنا من أعمالهم التي يقومون بها بأمر الله تعالى.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ماذا يتضمن الإيمان بالكتب المنزلة على الرسل ؟', '["المرتبة الثانية الإيمان.", "الخشية : هي الخوف المبني على العلم.", "الاستعانة : هي طلب العون من الله.", "يتضمن الإ يمان بالكتب أمرين وهما: 1) الإيمان بأن نزولها من عند"]'::jsonb, 3, 'يتضمن الإ يمان بالكتب أمرين وهما: 1) الإيمان بأن نزولها من عند. الأصول الثلاثة- للمبتدئين 2) الإيمان بما علمنا اسمهوما لم نعلم اسمه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'ماذا يتضمن الإيمان بالرسل ؟', '["يتضمن الإيمان بالرسل أربعة أمور وهي: 1) الإيمان بأن رسالتهم حق من الله تعالى", "الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك وأهله .", "القصَد، وال توجَّه .", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله."]'::jsonb, 0, 'يتضمن الإيمان بالرسل أربعة أمور وهي: 1) الإيمان بأن رسالتهم حق من الله تعالى. 2) الإيمان بمن علمنا اسمه منهم ومن لم نعلم اسمه. 3) تصديق ما صح عنهم من أخبارهم. 4) العمل بشريعة من أرسل إلينا منهم هو خاتمهم المرسل إلى جميع الناس.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ماذا يتضمن الإيمان باليوم الآخر؟', '["العمل الصالح هو العمل الموافق لسنة رسول الله .", "هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "يتضمن الإيمان باليوم ثلاثة أمور وهي: 1) الإيمان بالبعث وهوإحياء الموتى حين ينفخ في الصور النفخة الثانية فيقوم الناس لرب ", "هي الطريقة المائلة عن الشرك إلى التوحيد ."]'::jsonb, 2, 'يتضمن الإيمان باليوم ثلاثة أمور وهي: 1) الإيمان بالبعث وهوإحياء الموتى حين ينفخ في الصور النفخة الثانية فيقوم الناس لرب العالمين قال تعالى: ﱥﭐ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝﱞ ﱟ ﱠ ﱡ ﱢ ﱣﱤ ﱥ ﱦﱧ ﱨ ﱩ ﱪ ﱫ ﱤ [ الأنبياء: 104]. 2) الإيمان بالحساب والجزاء . 3) الإيمان بالجنة والنار .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'easy', 'mc', 'ماذا يتضمن الإيمان بالقدر؟', '["الصلوات الخمس المفروضة.", "الخشية : هي الخوف المبني على العلم.", "أقسم الله في هذه الس ورة بالعصر الذي هو الدهر وهو محل الحوادث من خير وشر .", "يتضمن الإيمان بالقدر خيره وشره أربعة أمور : لشيخ الإسلام محمد بن عبدالوهاب رحمه الله 1) الإيمان بأن الله تعالى علم بكل ش"]'::jsonb, 3, 'يتضمن الإيمان بالقدر خيره وشره أربعة أمور : لشيخ الإسلام محمد بن عبدالوهاب رحمه الله 1) الإيمان بأن الله تعالى علم بكل ش يء. 2) ايمان بأن الله كتب ذلك في اللوح المحفوظ . 3) الإيمان بأن جميع الكائنات لا تكون إلا بمشية الله. 4) الإيمان بأن جميع الكائنات مخلوقة لله.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'ما هو الإحسان في الشرع؟', '["دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] .", "القصَد، وال توجَّه .", "الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »", "الاستعانة : هي طلب العون من الله."]'::jsonb, 2, 'الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ما الدليل على ر كن الإحسان؟', '["هاجر إلى المدينة النبوية.", "الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128]", "الدليل قوله تعالى : ﱥﭐ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶ ﱤ [المائدة: 3].", "رجاء الإنسان في لقاء ربه في الآخرة."]'::jsonb, 1, 'الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 المؤلف', 'medium', 'mc', 'ما هي حقوق النبي علينا ؟', '["الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "هاجر إلى المدينة النبوية.", "حقوق الن ي كثيرة منها 1) الإيمان بنبوته ورسالته ", "المرتبة الثانية الإيمان."]'::jsonb, 2, 'حقوق الن ي كثيرة منها 1) الإيمان بنبوته ورسالته . 2) محبته أكثر من المال والولد والنفس 3) طاعته فيما أمر . 4) تصديقه فيما أخبر 5) اجتناب ما نهى عنه وزجر 6) الرد على كل من خالف ما دعا إليه الن ي .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ما معنى الهجرة في الإسل م؟', '["الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "الدليل، قوله تعالى: ﱥﭐ ﱁ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋ ﱌ ﱍ ﱎ ﱏ ﱐ ﱑ ﱤ [سورة العصر: 1-3.]", "الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام ", "رجاء الإنسان في لقاء ربه في الآخرة."]'::jsonb, 2, 'الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'easy', 'mc', 'ما حكم الهجرة على هذه الأمة؟', '["الاستعانة : هي طلب العون من الله.", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "الهجرة فريضة على هذه الأمة من بلد الشرك إلى بلد الإسلام، وهي باقية إلى أن تقوم الساعة", "ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة."]'::jsonb, 2, 'الهجرة فريضة على هذه الأمة من بلد الشرك إلى بلد الإسلام، وهي باقية إلى أن تقوم الساعة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'إلى أين هاجر النب ي ؟', '["نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "هي الطريقة المائلة عن الشرك إلى التوحيد .", "هاجر إلى المدينة النبوية", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] ."]'::jsonb, 2, 'هاجر إلى المدينة النبوية.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما هي شر ائع الإسلم التي أنزلت في المدينة؟', '["أي طريقُ هُ الد يني الذي يسير عليه الن ي .", "كل شرائع الإسلام ما عدا التوحيد والصلاة ، مثل الزكاة والصوم والحج والجهاد والأذان، والأمر بالمعروف، والنهي عن المنكر، وغ", "هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة.", "هي الطريقة المائلة عن الشرك إلى التوحيد ."]'::jsonb, 1, 'كل شرائع الإسلام ما عدا التوحيد والصلاة ، مثل الزكاة والصوم والحج والجهاد والأذان، والأمر بالمعروف، والنهي عن المنكر، وغي ر ذلك من شرائع الإسلام. الأصول الثلاثة- للمبتدئين', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 النبي', 'easy', 'mc', 'كم سنة أمضاها النبي بعد البعثة؟', '["أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة"]'::jsonb, 3, 'ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 النبي', 'medium', 'mc', 'ما الدليل على أن النبي بُعث إلى الناس عامة؟', '["الاستغاثة : هي طلب الغوث وهو الإنقاذ من الشدة والهلاك .", "رجاء الإنسان في لقاء ربه في الآخرة.", "الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 ", "الاستعانة : هي طلب العون من الله."]'::jsonb, 2, 'الدليل قوله تعالى: ﱥﭐ ﲑ ﲒ ﲓ ﲔ ﲕ ﲖ ﲗ ﲘ ﱤ [الأعراف : 158 .]', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما الدليل على أن الله لا يرض ى لعباده إلا بالدين ا لذي بعث به محمدً ا؟', '["هو اعتقاد بالقلب؛ وقول اللسان؛ وعمل الجوا رح.", "الاستعاذة: هي طلب الحماية من مكروه.", "الدليل قوله تعالى : ﱥﭐ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶ ﱤ [المائدة: 3]", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] ."]'::jsonb, 2, 'الدليل قوله تعالى : ﱥﭐ ﱫ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶ ﱤ [المائدة: 3].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '👤 النبي', 'easy', 'mc', 'ما الدليل على موت النبي وموت جميع البشر؟', '["الب ضع بكسر الباء العدد من الثلاثة إلى التسعة .", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31]", "الدليل قوله تعالى: ﱥﭐ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﱤ [التغابن: 7].", "هو طمع الإنسان في أمر قريب المنال يمكن أن ي ناله."]'::jsonb, 1, 'الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'medium', 'mc', 'ما الدليل على بعث الناس بعد موته م؟', '["الدليل قوله تعالى: ﱥﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶﱤ [طه: 55 ]", "هو الاعتماد على الله وتفويض الأمور إليه مع الأخذ بالأسباب المشروعة.", "دليل الصيام قوله تعالى: ﱥﭐ ﱓ ﱔ ﱕ ﱖ ﱗ ﱘ ﱙ ﱚ ﱛ ﱜ ﱝ ﱞ ﱟ ﱠ ﱡ ﱤ [ البقرة 183] .", "الدليل قوله تعالى: ﱥﭐ ﲬ ﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﲳ ﲴ ﲵ ﲶ ﲷ ﲸﲹ ﲺ ﲻ ﲼ ﲽ ﱤ [سورة البينة: 5]."]'::jsonb, 0, 'الدليل قوله تعالى: ﱥﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵﱶﱤ [طه: 55 ]. وقوله تعالى ﱥﭐ ﱬ ﱭ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷﱤ [نوح : 17-18 ]، وبعد ال بعث محاسبون ومجزيون بأعمالهم. لشيخ الإسلام محمد بن عبدالوهاب رحمه الله', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما دليل الجزاء بعد الموت؟', '["الهجرة: الانتقال من بلد الشرك إلى بلد الإسلام . لشيخ الإسلام محمد بن عبدالوهاب رحمه الله", "نوعان : 1) آيات كونية : هي المخلوقات. 2) آيات شرعية : هي الوحي الذي أنزله الله على رسله.", "الذي رباني بنعمه وهو المستحق للعبادة دون سواه.", "الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31]"]'::jsonb, 3, 'الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما الدليل على كفر من كذب بالبعث؟', '["هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "العمل الصالح هو العمل الموافق لسنة رسول الله .", "الدليل قوله تعالى: ﱥﭐ ﲃ ﲄ ﲅ ﲆ ﲇ ﲈ ﲉ ﲊ ﲋ ﱤ [النجم: 31].", "الدليل قوله تعالى: ﱥﭐ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﱤ [التغابن: 7]"]'::jsonb, 3, 'الدليل قوله تعالى: ﱥﭐ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣﲤ ﲥ ﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬﲭ ﲮ ﲯ ﲰ ﲱ ﲲ ﱤ [التغابن: 7].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📚 المسائل الأربع', 'medium', 'mc', 'ما هي وظيفة جميع الرسل؟', '["هو إلزام الإنسان نفسه بش يء ما لم يلزمه الله به.", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "هي الطريقة المائلة عن الشرك إلى التوحيد .", "وظيفة الرسل الدعوة إلى وإقام ة الحجة على الخلق فهم مبشرون برحمة الله ومنذرون من عذا ب الله"]'::jsonb, 3, 'وظيفة الرسل الدعوة إلى وإقام ة الحجة على الخلق فهم مبشرون برحمة الله ومنذرون من عذا ب الله.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ما الدليل على أن الرسل مبشرين ومنذرين؟', '["الدليل قوله تعالى: ﱥﭐ ﳍ ﳎ ﳏ ﳐ ﳑ ﳒ ﳓ ﳔ ﳕﱤ [النحل: 128].", "الدليل قوله تعالى: ﱥﭐ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸﱹ ﱤ [النساء: 165]", "الإحسان ، ركن واحد وهو «أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك »", "ثلاث وعشر و ن سنة؛ ثلاث عشر سنة في مكة المكرمة وعشر سنين في المدينة."]'::jsonb, 1, 'الدليل قوله تعالى: ﱥﭐ ﱮ ﱯ ﱰ ﱱ ﱲ ﱳ ﱴ ﱵ ﱶ ﱷ ﱸﱹ ﱤ [النساء: 165].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'من أول الرسل ومن آخرهم ؟', '["قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين", "الدليل على موته قوله تعالى: ﱥﭐ ﳐ ﳑ ﳒ ﳓﳔ ﳕ ﳖ ﳗ ﳘ ﳙ ﳚ ﳛ ﳜ ﱤ [الزم ر: 30-31].", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163]", "الب ضع بكسر الباء العدد من الثلاثة إلى التسعة ."]'::jsonb, 2, 'أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'medium', 'mc', 'ما الدليل أن الله بعث إلى كل أمة رسولا؟', '["الخشية : هي الخوف المبني على العلم.", "أولهم نوح ، وآخرهم محمد والدليل قوله تعالى: ﱥﭐ ﱂ ﱃ ﱄ ﱅ ﱆ ﱇ ﱈ ﱉ ﱊ ﱋﱌ ﱤ [ورة النساء: 163].", "الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36]", "قَالَ الشَّاف عيُّ - تَعَالَى -« : السورة لكفتهم . الأصول الثلاثة- للمبتدئين"]'::jsonb, 2, 'الدليل قوله تعالى: ﱥﭐ ﱤ ﱥ ﱦ ﱧ ﱨ ﱩ ﱪ ﱫ ﱬ الأصول الثلاثة- للمبتدئين ﱭ ﱮﱯ ﱤ [النحل: 36].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📿 الدين', 'hard', 'mc', 'ماذا افترض الله على جميع الخلق؟', '["نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "الصبر هو حبس النفس على طاعة الله وعن م عصيته وعلى أقدار الله المؤلمة .", "هو اعتقاد بالقلب؛ وقول اللسان؛ وعمل الجوا رح.", "افترض الله على جميع العباد الكفر بالطاغوت والإيمان بالله و الدليل قوله تعالى: ﱥﭐ ﳎ ﳏ ﳐ ﳑﳒ ﳓ ﳔ ﳕ ﳖ ﳗﳘ ﳙ ﳚ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﳡ ﱤ"]'::jsonb, 3, 'افترض الله على جميع العباد الكفر بالطاغوت والإيمان بالله و الدليل قوله تعالى: ﱥﭐ ﳎ ﳏ ﳐ ﳑﳒ ﳓ ﳔ ﳕ ﳖ ﳗﳘ ﳙ ﳚ ﳛ ﳜ ﳝ ﳞ ﳟ ﳠ ﳡ ﱤ [ورة البقرة : 256].', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'ما هو الطاغوت وما رؤوسه؟', '["دليل الحج قوله تعالى: ﱥﭐ ﲝ ﲞ ﲟ ﲠ ﲡ ﲢ ﲣ ﲤ ﲥﲦ ﲧ ﲨ ﲩ ﲪ ﲫ ﲬ ﲭ ﱤ [ورة آل عمران : 97.]", "قال ابن القيم - تعالى-: الطاغوت ما تجاوز به العبد حده من معبود، أو متبوع، أو مطاع", "نفقة مال محدد بوقت محدد لفئة محددة شرعً ا كما جاء في النصوص الشرعية .", "الهجرة فريضة على هذه الأمة من بلد الشرك إلى بلد الإسلام، وهي باقية إلى أن تقوم الساعة."]'::jsonb, 1, 'قال ابن القيم - تعالى-: الطاغوت ما تجاوز به العبد حده من معبود، أو متبوع، أو مطاع. والطواغيت كثيرة، ورؤوسهم خمسة: إبليس لعنه الله، ومن عُ بد وهو راض، ومن دعا الناس إلى عبادة نفسه، ومن ا دعى شيئً ا من علم الغيب، ومن حكم بغير ما أنزل الله.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '1- النية', 'easy', 'mc', 'من فوائد الحديث (1- النية): الحث على الإخلاص ؟', '["نعم، ينبغي على الإنسان أن يشتغل بما فيه صلاحه في الدنيا والآخرة", "نعم، إن الله لا يقبل من عباده إلا الصالح الطيب من العمل", "نعم، الحث على الإخلاص ", "نعم، المؤمنونإخوة فيما بينهم ."]'::jsonb, 2, 'نعم، الحث على الإخلاص .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '1- النية', 'medium', 'mc', 'من فوائد الحديث (1- النية): فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله؟', '["نعم، ينبغي على من جهل أمرًا أن يسأل عنـه أهل العلم.", "نعم، فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله", "نعم، استحباب الإصلاح بين الناس بالعدل", "نعم، أن الإسلامدين اتباع لا دين ابتداع."]'::jsonb, 1, 'نعم، فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '1- النية', 'hard', 'mc', 'من فوائد الحديث (1- النية): الإيمان بوجوده سبحانه ؟', '["نعم، المر بالكل من الطيبات", "نعم، الإيمان بوجوده سبحانه ", "نعم، رة الإسلام شملت كل شيء حتى الحيوان.", "نعم، إثبات يوم القيامة وأن فيها كربًا عظيمة."]'::jsonb, 1, 'نعم، الإيمان بوجوده سبحانه .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- جبريل', 'easy', 'mc', 'من فوائد الحديث (2- جبريل): أن المحدثات في الدين بدع وكُ بدعة ضلالة؟', '["نعم، الحث على تنفيس الكرب عن المؤمن", "نعم، على المسلم أن يتصف بالحلم والتأنـي وهما ضد الغضب", "نعم، أن المحدثات في الدين بدع وكُ بدعة ضلالة", "نعم، المر بالكل من الطيبات"]'::jsonb, 2, 'نعم، أن المحدثات في الدين بدع وكُ بدعة ضلالة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- جبريل', 'medium', 'mc', 'من فوائد الحديث (2- جبريل): أن الإسلامدين اتباع لا دين ابتداع؟', '["نعم، ينبغي على من جهل أمرًا أن يسأل عنـه أهل العلم.", "نعم، أن الإسلامدين اتباع لا دين ابتداع", "نعم، ينبغي على المسلم أن يراقب الله في جميع أحواله وأو قاته.", "نعم، حسن تعليم ا بضرب المثال المقنعة 115 لأبي زكريا محيي الدين النووي"]'::jsonb, 1, 'نعم، أن الإسلامدين اتباع لا دين ابتداع.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- جبريل', 'hard', 'mc', 'من فوائد الحديث (2- جبريل): حلال بينّ كلل يعرفه؟', '["نعم، ا لا تنفعه طـاعـ ة الطائعين ولا تضره معصي ة العاصين.", "نعم، فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله.", "نعم، حلال بينّ كلل يعرفه", "نعم، الحث على حفظ اللسان"]'::jsonb, 2, 'نعم، حلال بينّ كلل يعرفه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- الإيمان', 'easy', 'mc', 'من فوائد الحديث (2- الإيمان): أن الله أنزل على رسوله الكتاب وب فيه للأم ة ما تحتاج إليه من حلال وحرام؟', '["نعم، أن الله تعالى فرض فرائض وأمر بالمحافظة عليها", "نعم، الإيمان بالقضاء والقدر", "نعم، صب على طـاعة الله.", "نعم، أن الله أنزل على رسوله الكتاب وب فيه للأم ة ما تحتاج إليه من حلال وحرام"]'::jsonb, 3, 'نعم، أن الله أنزل على رسوله الكتاب وب فيه للأم ة ما تحتاج إليه من حلال وحرام.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- الإيمان', 'medium', 'mc', 'من فوائد الحديث (2- الإيمان): هناك منزلة بين الحلال والحرام تشتبه اختلط فيها المران فمن اتقاها فقد نجا؟', '["نعم، ا منزه عن الظلم وحرمـه على عباده", "نعم، إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها.", "نعم، العمل الصالح سبب لدخول الجنة", "نعم، هناك منزلة بين الحلال والحرام تشتبه اختلط فيها المران فمن اتقاها فقد نجا"]'::jsonb, 3, 'نعم، هناك منزلة بين الحلال والحرام تشتبه اختلط فيها المران فمن اتقاها فقد نجا.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- الإحسان', 'hard', 'mc', 'من فوائد الحديث (2- الإحسان): وجوب النصيحة بين المسلم؟', '["نعم، فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله.", "نعم، وجوب النصيحة بين المسلم", "نعم، أن الإسلامدين اتباع لا دين ابتداع.", "نعم، تنافس الصحابة في عمل الخيات"]'::jsonb, 1, 'نعم، وجوب النصيحة بين المسلم', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '2- الساعة', 'easy', 'mc', 'من فوائد الحديث (2- الساعة): من دخل في الإسلام يحرم مالـه ودمــه وعرضــه؟', '["نعم، من دخل في الإسلام يحرم مالـه ودمــه وعرضــه", "نعم، وجوب تغي ي المنكر بكل ما يمكن بيد أو لسان أو بالقلب.", "نعم، ينبغي على الإنسان أن يشتغل بما فيه صلاحه في الدنيا والآخرة", "نعم، الحث على حفظ اللسان"]'::jsonb, 0, 'نعم، من دخل في الإسلام يحرم مالـه ودمــه وعرضــه', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '3- أركان الإسلام', 'medium', 'mc', 'من فوائد الحديث (3- أركان الإسلام): اجتناب ما نهى عنـه الرسول ؟', '["نعم، على المسلم أن يبأحكامه وأ مور حياته على اليقين.", "نعم، الحث على حفظ اللسان", "نعم، اجتناب ما نهى عنـه الرسول ", "نعم، أن معاداة أولياء الله من كبائر الذنوب"]'::jsonb, 2, 'نعم، اجتناب ما نهى عنـه الرسول .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '3- أركان الإسلام', 'hard', 'mc', 'من فوائد الحديث (3- أركان الإسلام): امتثال أمر الرسول بقدر الاستطاعة؟', '["نعم، امتثال أمر الرسول بقدر الاستطاعة", "نعم، ا منزه عن الظلم وحرمـه على عباده", "نعم، إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها.", "نعم، صب على طـاعة الله."]'::jsonb, 0, 'نعم، امتثال أمر الرسول بقدر الاستطاعة', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '3- أركان الإسلام', 'easy', 'mc', 'من فوائد الحديث (3- أركان الإسلام): النهي عن كثرة السؤال لغي حـاجة؟', '["نعم، إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها.", "نعم، الحث على الصدقــة", "نعم، النهي عن كثرة السؤال لغي حـاجة", "نعم، حرص الصحابة على العلم"]'::jsonb, 2, 'نعم، النهي عن كثرة السؤال لغي حـاجة', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '4- القدر', 'medium', 'mc', 'من فوائد الحديث (4- القدر): المر بالكل من الطيبات؟', '["نعم، العمل الصالح سبب لدخول الجنة", "نعم، المؤمنونإخوة فيما بينهم .", "نعم، الحرص على الكلام الطيب", "نعم، المر بالكل من الطيبات"]'::jsonb, 3, 'نعم، المر بالكل من الطيبات', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '4- القدر', 'hard', 'mc', 'من فوائد الحديث (4- القدر): إن الله لا يقبل من عباده إلا الصالح الطيب من العمل؟', '["نعم، الإيمان بالقضاء والقدر", "نعم، إن الله لا يقبل من عباده إلا الصالح الطيب من العمل", "نعم، اجتناب ما نهى عنـه الرسول .", "نعم، ا منزه عن الظلم وحرمـه على عباده"]'::jsonb, 1, 'نعم، إن الله لا يقبل من عباده إلا الصالح الطيب من العمل', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '5- البدعة', 'easy', 'mc', 'من فوائد الحديث (5- البدعة): على المسلم أن يبأحكامه وأ مور حياته على اليقين؟', '["نعم، تنافس الصحابة في عمل الخيات", "نعم، على المسلم أن يبأحكامه وأ مور حياته على اليقين", "نعم، أن المحدثات في الدين بدع وكُ بدعة ضلالة.", "نعم، فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله."]'::jsonb, 1, 'نعم، على المسلم أن يبأحكامه وأ مور حياته على اليقين.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '6- الشبهات', 'medium', 'mc', 'من فوائد الحديث (6- الشبهات): ينبغي على الإنسان أن يشتغل بما فيه صلاحه في الدنيا والآخرة؟', '["نعم، وجوب السمع والطاعة لولي المــر مالم يكن في معصية", "نعم، ينبغي على الإنسان أن يشتغل بما فيه صلاحه في الدنيا والآخرة", "نعم، أن أوامر ا قسمان فريضة ونافلـة", "نعم، الحث على حفظ اللسان"]'::jsonb, 1, 'نعم، ينبغي على الإنسان أن يشتغل بما فيه صلاحه في الدنيا والآخرة', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '7- النصيحة', 'hard', 'mc', 'من فوائد الحديث (7- النصيحة): المؤمنونإخوة فيما بينهم ؟', '["نعم، ينبغي على من جهل أمرًا أن يسأل عنـه أهل العلم.", "نعم، الحرص على الكلام الطيب", "نعم، رة الإسلام شملت كل شيء حتى الحيوان.", "نعم، المؤمنونإخوة فيما بينهم "]'::jsonb, 3, 'نعم، المؤمنونإخوة فيما بينهم .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '7- النصيحة', 'easy', 'mc', 'من فوائد الحديث (7- النصيحة): من شرط ايمان الكامل أن يحب المسلم الخي لخيه المسلم ؟', '["نعم، أن الجزاء من جنس العمل", "نعم، أن الله تعالى فرض فرائض وأمر بالمحافظة عليها", "نعم، ينبغي على المسلم أن يراقب الله في جميع أحواله وأو قاته.", "نعم، من شرط ايمان الكامل أن يحب المسلم الخي لخيه المسلم "]'::jsonb, 3, 'نعم، من شرط ايمان الكامل أن يحب المسلم الخي لخيه المسلم .', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '8- الجهاد', 'medium', 'mc', 'من فوائد الحديث (8- الجهاد): احترام دماء المسلم؟', '["نعم، احترام دماء المسلم", "نعم، امتثال أمر الرسول بقدر الاستطاعة", "نعم، أن الله تعالى فرض فرائض وأمر بالمحافظة عليها", "نعم، من علامات الإثم أن يكون في النفس ما يكره ا طِّ لاعأ الناس عليـه."]'::jsonb, 0, 'نعم، احترام دماء المسلم', 'ar');
