INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '21- الاستقامة', 'medium', 'mc', 'من فوائد الحديث (21- الاستقامة): من علامات الإثم أن يكون في النفس ما يكره ا طِّ لاعأ الناس عليـه؟', '["نعم، الصمت خي من الكلام الذي لا فائدة فيه", "نعم، من علامات الإثم أن يكون في النفس ما يكره ا طِّ لاعأ الناس عليـه", "نعم، أنــه لا يحكم لحد بمجرد دعواه وهواه", "نعم، حلال بينّ كلل يعرفه."]'::jsonb, 1, 'نعم، من علامات الإثم أن يكون في النفس ما يكره ا طِّ لاعأ الناس عليـه.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '22- الجنة', 'hard', 'mc', 'من فوائد الحديث (22- الجنة): مشروعية الموعظــة للناس 86 الأربعون النووية- للمبتدئين؟', '["نعم، ينبغي على المسلم أن يحرص على ما يدخل الجنة ويبعد عن النار", "نعم، حسن تعليم ا بضرب المثال المقنعة 115 لأبي زكريا محيي الدين النووي", "نعم، حرص الصحابة على العلم", "نعم، مشروعية الموعظــة للناس 86 الأربعون النووية- للمبتدئين"]'::jsonb, 3, 'نعم، مشروعية الموعظــة للناس 86 الأربعون النووية- للمبتدئين', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '22- الجنة', 'easy', 'mc', 'من فوائد الحديث (22- الجنة): لزوم تقوى الله تعا؟', '["نعم، وجوب الثبات على الإيمان بالقول والعمل", "نعم، أن الإسلامدين اتباع لا دين ابتداع.", "نعم، لزوم تقوى الله تعا", "نعم، أن الجزاء من جنس العمل"]'::jsonb, 2, 'نعم، لزوم تقوى الله تعا', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '22- الجنة', 'medium', 'mc', 'من فوائد الحديث (22- الجنة): وجوب السمع والطاعة لولي المــر مالم يكن في معصية؟', '["نعم، وجوب السمع والطاعة لولي المــر مالم يكن في معصية", "نعم، تنافس الصحابة في عمل الخيات", "نعم، وجوب إكرام الجار والضيف", "نعم، صب عن معصيـة الله."]'::jsonb, 0, 'نعم، وجوب السمع والطاعة لولي المــر مالم يكن في معصية', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '23- جوامع الخير', 'hard', 'mc', 'من فوائد الحديث (23- جوامع الخير): حرص الصحابة على العلم؟', '["نعم، فضل الذكــر وعظم أجره", "نعم، صب على طـاعة الله.", "نعم، المر بالكل من الطيبات", "نعم، حرص الصحابة على العلم"]'::jsonb, 3, 'نعم، حرص الصحابة على العلم', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '23- جوامع الخير', 'easy', 'mc', 'من فوائد الحديث (23- جوامع الخير): ينبغي على المسلم أن يحرص على ما يدخل الجنة ويبعد عن النار؟', '["نعم، الإيمان بوجوده سبحانه .", "نعم، صب على طـاعة الله.", "نعم، ينبغي على المسلم أن يحرص على ما يدخل الجنة ويبعد عن النار", "نعم، مشروعية الموعظــة للناس 86 الأربعون النووية- للمبتدئين"]'::jsonb, 2, 'نعم، ينبغي على المسلم أن يحرص على ما يدخل الجنة ويبعد عن النار', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '24- فضل الله', 'medium', 'mc', 'من فوائد الحديث (24- فضل الله): أن الله تعالى فرض فرائض وأمر بالمحافظة عليها؟', '["نعم، وجوب تغي ي المنكر بكل ما يمكن بيد أو لسان أو بالقلب.", "نعم، الحث على الإخلاص .", "نعم، أنــه لا يحكم لحد بمجرد دعواه وهواه", "نعم، أن الله تعالى فرض فرائض وأمر بالمحافظة عليها"]'::jsonb, 3, 'نعم، أن الله تعالى فرض فرائض وأمر بالمحافظة عليها', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '24- فضل الله', 'hard', 'mc', 'من فوائد الحديث (24- فضل الله): إن الله تعالى حرم أشياء فلا يجوز تناولها ولا القرب منها؟', '["نعم، وجوب النصيحة بين المسلم", "نعم، إن الله تعالى حرم أشياء فلا يجوز تناولها ولا القرب منها", "نعم، الإيمان بالقضاء والقدر", "نعم، اجتناب ما نهى عنـه الرسول ."]'::jsonb, 1, 'نعم، إن الله تعالى حرم أشياء فلا يجوز تناولها ولا القرب منها', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '25- الصدقة', 'easy', 'mc', 'من فوائد الحديث (25- الصدقة): علو همة الصحابة ، فإنهم لا يسألون إلا عما يفيدهمفي الدنيا والآخرة أو فيهما جميعً ا؟', '["نعم، علو همة الصحابة ، فإنهم لا يسألون إلا عما يفيدهمفي الدنيا والآخرة أو فيهما جميعً ا", "نعم، أن الإسلامدين اتباع لا دين ابتداع.", "نعم، حرص الإسلام على حفظ العراض والنفس والدين", "نعم، الحث على معونـة الرجل أخاه"]'::jsonb, 0, 'نعم، علو همة الصحابة ، فإنهم لا يسألون إلا عما يفيدهمفي الدنيا والآخرة أو فيهما جميعً ا.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '25- الصدقة', 'medium', 'mc', 'من فوائد الحديث (25- الصدقة): أن الزهد في الدنيا من أسباب محبة الله لعبده ومحبة الناس لـه؟', '["نعم، إن الله تعالى حرم أشياء فلا يجوز تناولها ولا القرب منها", "نعم، على المسلم أن يتصف بالحلم والتأنـي وهما ضد الغضب", "نعم، الحث على حسن الخلق", "نعم، أن الزهد في الدنيا من أسباب محبة الله لعبده ومحبة الناس لـه"]'::jsonb, 3, 'نعم، أن الزهد في الدنيا من أسباب محبة الله لعبده ومحبة الناس لـه', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '26- الصدقة', 'hard', 'mc', 'من فوائد الحديث (26- الصدقة): أن الضرر يزال ويبنى على ذلك كثي من الحكام؟', '["نعم، أن المحدثات في الدين بدع وكُ بدعة ضلالة.", "نعم، أن الضرر يزال ويبنى على ذلك كثي من الحكام", "نعم، ينبغي على من جهل أمرًا أن يسأل عنـه أهل العلم.", "نعم، العمل الصالح سبب لدخول الجنة"]'::jsonb, 1, 'نعم، أن الضرر يزال ويبنى على ذلك كثي من الحكام', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '27- البر والإثم', 'easy', 'mc', 'من فوائد الحديث (27- البر والإثم): أنــه لا يحكم لحد بمجرد دعواه وهواه؟', '["نعم، أنــه لا يحكم لحد بمجرد دعواه وهواه", "نعم، صب عن معصيـة الله.", "نعم، حسن تعليم ا بضرب المثال المقنعة 115 لأبي زكريا محيي الدين النووي", "نعم، إثبات يوم القيامة وأن فيها كربًا عظيمة."]'::jsonb, 0, 'نعم، أنــه لا يحكم لحد بمجرد دعواه وهواه', 'ar');
