INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '28- السنة', 'hard', 'mc', 'من فوائد الحديث (28- السنة): إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها؟', '["نعم، وجوب النصيحة بين المسلم", "نعم، على المسلم أن يجعل سؤاله واستعانتـه بالله وحده", "نعم، أن الإسلامدين اتباع لا دين ابتداع.", "نعم، إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها"]'::jsonb, 3, 'نعم، إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '29- اللسان', 'easy', 'mc', 'من فوائد الحديث (29- اللسان): الحث على تنفيس الكرب عن المؤمن؟', '["نعم، امتثال أمر الرسول بقدر الاستطاعة", "نعم، حرص الإسلام على حفظ العراض والنفس والدين", "نعم، على المسلم أن يبأحكامه وأ مور حياته على اليقين.", "نعم، الحث على تنفيس الكرب عن المؤمن"]'::jsonb, 3, 'نعم، الحث على تنفيس الكرب عن المؤمن', 'ar');
