INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '29- اللسان', 'hard', 'mc', 'من فوائد الحديث (29- اللسان): إثبات يوم القيامة وأن فيها كربًا عظيمة؟', '["نعم، الحث على معونـة الرجل أخاه", "نعم، إثبات يوم القيامة وأن فيها كربًا عظيمة", "نعم، الحث على الصدقــة", "نعم، النهي عن كثرة السؤال لغي حـاجة"]'::jsonb, 1, 'نعم، إثبات يوم القيامة وأن فيها كربًا عظيمة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '30- الحدود', 'easy', 'mc', 'من فوائد الحديث (30- الحدود): استعمال التفصيل بعد الإجمال ليكون أوقع في النفس وأدعى للقبول؟', '["نعم، وجوب الثبات على الإيمان بالقول والعمل", "نعم، الصمت خي من الكلام الذي لا فائدة فيه", "نعم، استعمال التفصيل بعد الإجمال ليكون أوقع في النفس وأدعى للقبول", "نعم، حث الإسلام على خلق الحياء"]'::jsonb, 2, 'نعم، استعمال التفصيل بعد الإجمال ليكون أوقع في النفس وأدعى للقبول', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '30- الحدود', 'medium', 'mc', 'من فوائد الحديث (30- الحدود): أن ما يعمله الإنسان في هذه الدنيا من الحسنات والسيئات قد كتبه الله تعالى في اللوح المحفوظ؟', '["نعم، استحباب الإصلاح بين الناس بالعدل", "نعم، تنافس الصحابة في عمل الخيات", "نعم، الإيمان بالقضاء والقدر", "نعم، أن ما يعمله الإنسان في هذه الدنيا من الحسنات والسيئات قد كتبه الله تعالى في اللوح المحفوظ"]'::jsonb, 3, 'نعم، أن ما يعمله الإنسان في هذه الدنيا من الحسنات والسيئات قد كتبه الله تعالى في اللوح المحفوظ.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '31- الزهد', 'hard', 'mc', 'من فوائد الحديث (31- الزهد): أن معاداة أولياء الله من كبائر الذنوب؟', '["نعم، ضعف المخلوقين وافتقارهم إلى ا", "نعم، أن معاداة أولياء الله من كبائر الذنوب", "نعم، المؤمنونإخوة فيما بينهم .", "نعم، على المسلم أن يبأحكامه وأ مور حياته على اليقين."]'::jsonb, 1, 'نعم، أن معاداة أولياء الله من كبائر الذنوب', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '31- الزهد', 'easy', 'mc', 'من فوائد الحديث (31- الزهد): أن أوامر ا قسمان فريضة ونافلـة؟', '["نعم، أن أوامر ا قسمان فريضة ونافلـة", "نعم، المر بالكل من الطيبات", "نعم، أن الزهد في الدنيا من أسباب محبة الله لعبده ومحبة الناس لـه", "نعم، التزهيد في الدنيا وأن يتخذها الإنسان دار إقامــة."]'::jsonb, 0, 'نعم، أن أوامر ا قسمان فريضة ونافلـة', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '32- الضرر', 'medium', 'mc', 'من فوائد الحديث (32- الضرر): سعة رحمة ا ولطفـه بعباده حيث رفع عنهم الإثم إذا صدرت منهم المعصية على هذه الوجوه الثلاثة؟', '["نعم، حرص الإسلام على حفظ العراض والنفس والدين", "نعم، سعة رحمة ا ولطفـه بعباده حيث رفع عنهم الإثم إذا صدرت منهم المعصية على هذه الوجوه الثلاثة", "نعم، الحث على الاكثار من الصلاة؛ لنها نور للمسلم", "نعم، إنَّ لتغيي المنكـر درجات فلا يغيه أحد إلا بالذي يستطيع منها."]'::jsonb, 1, 'نعم، سعة رحمة ا ولطفـه بعباده حيث رفع عنهم الإثم إذا صدرت منهم المعصية على هذه الوجوه الثلاثة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '33- القضاء', 'hard', 'mc', 'من فوائد الحديث (33- القضاء): التزهيد في الدنيا وأن يتخذها الإنسان دار إقامــة؟', '["نعم، صب على طـاعة الله.", "نعم، وجوب النصيحة بين المسلم", "نعم، الإحسان إلى كل الخلق والرفق بهم والشفقة عليهم", "نعم، التزهيد في الدنيا وأن يتخذها الإنسان دار إقامــة"]'::jsonb, 3, 'نعم، التزهيد في الدنيا وأن يتخذها الإنسان دار إقامــة.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '33- القضاء', 'easy', 'mc', 'من فوائد الحديث (33- القضاء): حسن تعليم ا بضرب المثال المقنعة 115 لأبي زكريا محيي الدين النووي؟', '["نعم، فضلالهجرة من بلد الشرك إلى بلد الإسلام ابتغاء مرضات الله.", "نعم، حسن تعليم ا بضرب المثال المقنعة 115 لأبي زكريا محيي الدين النووي", "نعم، فضل الذكــر وعظم أجره", "نعم، ضعف المخلوقين وافتقارهم إلى ا"]'::jsonb, 1, 'نعم، حسن تعليم ا بضرب المثال المقنعة 115 لأبي زكريا محيي الدين النووي', 'ar');